insert into public.ai_animations (lesson_id,tipo,status,model,roteiro,urls) values ('d1000000-d100-4d00-9000-0000000b0005','interactive','ready','handcrafted-interactive','{"titulo":"Cabine de DJ — 2× CDJ-3000 + DJM-A9","cenas":[{"numero":1,"titulo":"Mixe na cabine (áudio real)","modo":"widget","narracao":"Cabine club-standard com dois CDJ-3000 e o mixer DJM-A9, com áudio de verdade. Toque, pré-escute no fone, case o BPM e a fase, troque graves no EQ e faça a virada. Complete as 7 missões.","explicacao_texto":"Simulador fiel da cabine profissional. Motor de áudio Web Audio (grooves sintetizados — placeholder até plugarmos as faixas reais da SMU).","destaques":["2× CDJ-3000: jog, tempo, cue, hot cues, loop","DJM-A9: trim, EQ 3 bandas, color filter, crossfader","Pré-escuta no fone (CUE/PFL) e BEAT FX","Beatmatch real: BPM + fase"]}]}'::jsonb,'[{"html":"<!doctype html>\n<html lang=\"pt-BR\">\n<head>\n<meta charset=\"utf-8\">\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1, maximum-scale=1, user-scalable=no\">\n<link rel=\"icon\" href=\"data:,\">\n<title>Cabine de DJ — 2× CDJ-3000 + DJM-A9 — Simulador fiel (SMU)</title>\n<style>\n  :root{\n    --ink:#e9eef7; --muted:#8b97a9; --amber:#f4a02a; --orange:#ff7a1a;\n    --green:#37d07a; --red:#e0483f; --cyan:#39c0e6; --blue:#2e78ff;\n  }\n  *{box-sizing:border-box}\n  html,body{margin:0;height:100%}\n  body{\n    background:radial-gradient(1200px 700px at 50% -8%,#1b1e23,#0a0b0d 62%),#08090b;\n    color:var(--ink);\n    font-family:\"Inter\",system-ui,-apple-system,\"Segoe UI\",Roboto,sans-serif;\n    -webkit-font-smoothing:antialiased;user-select:none;overflow:hidden;\n    display:flex;align-items:flex-start;justify-content:center;\n  }\n  #stage{transform-origin:top center;flex:0 0 auto}\n  .booth{position:relative;width:1640px;display:flex;flex-direction:column;gap:9px;padding:12px;\n    background:linear-gradient(180deg,#2b2f36,#1f2228 10%,#191b1f 60%,#141518);\n    border:1px solid #0b0c0e;border-radius:16px;\n    box-shadow:0 30px 80px #000b, inset 0 1px 0 #ffffff10, inset 0 -2px 0 #0008;}\n\n  .util{display:flex;align-items:center;gap:8px;flex-wrap:wrap;\n    background:linear-gradient(180deg,#202329,#15171b);border:1px solid #0c0d0f;border-radius:11px;padding:7px 11px}\n  .brand{display:flex;align-items:baseline;gap:9px}\n  .brand b{font-size:17px;letter-spacing:1px;color:#eef2f8}\n  .brand .m{font-size:9.5px;letter-spacing:2px;color:#8a94a4;text-transform:uppercase}\n  .pill{font-size:10.5px;color:var(--muted);background:#0c0e12;border:1px solid #2a2f37;border-radius:16px;padding:4px 9px;display:flex;align-items:center;gap:6px;letter-spacing:.3px;white-space:nowrap}\n  .pill b{color:#fff}\n  .dot{width:8px;height:8px;border-radius:50%;background:var(--green);box-shadow:0 0 8px var(--green)}\n  .dot.off{background:#444;box-shadow:none}\n  .spacer{flex:1}\n  .btnp{font:inherit;font-size:11.5px;font-weight:700;border:0;border-radius:8px;padding:7px 12px;cursor:pointer;color:#07120b;background:linear-gradient(180deg,#5be59a,#27b566)}\n  .btnp.ghost{background:transparent;color:var(--muted);border:1px solid #2a2f37}\n  .mission{display:flex;align-items:center;gap:9px;background:#0c0e12;border:1px solid #2a2f37;border-radius:9px;padding:5px 10px;flex:1 1 380px;min-width:0}\n  .mission .idx{font-size:10px;color:var(--amber);font-weight:800;letter-spacing:1px;white-space:nowrap}\n  .mission .txt{font-size:11.5px;line-height:1.25;min-width:0}\n  .mission .txt b{color:#fff}\n  .mission .txt small{color:var(--muted)}\n  .mission .ok{color:var(--green);font-weight:800;font-size:16px}\n\n  .row{display:grid;grid-template-columns:1fr 470px 1fr;gap:10px;align-items:start}\n\n  /* ===== CDJ-3000 ===== */\n  .cdj{background:linear-gradient(180deg,#26292f,#1c1e23 40%,#161719);border:1px solid #0c0d0f;border-radius:13px;padding:11px;display:flex;flex-direction:column;gap:9px;\n    box-shadow:inset 0 1px 0 #ffffff10, inset 0 -2px 6px #0007}\n  .cdj .hdr{display:flex;justify-